  const scores = [u?.confidence, c?.confidence, h?.confidence].filter(Boolean).map(Number).map(s => s > 0 && s <= 1 ? Math.round(s * 100) : Math.round(s));
  if (!scores.length) continue;
  const avg = Math.round(scores.reduce((a,b)=>a+b,0)/scores.length);
  let rs = Number(r?.raziel_score||50); if (rs > 0 && rs <= 1) rs = Math.round(rs * 100);
  const verdict = r?.verdict||'UNKNOWN';
  const ac = scores.length;
  let tier = 'PROBE';
  const razielReviewed = verdict !== 'UNKNOWN';
  if (avg>=80 && (razielReviewed ? (rs>=70 && verdict==='CLEAR') : true) && ac>=2) tier='PRIME';
  else if (avg>=65 && (razielReviewed ? (rs>=55 && verdict!=='ABORT') : true)) tier='STRONG';
  const ring = u?.ring || (['SGOV','BIL'].includes(tk)?'Ring1':['PSLV','IBIT'].includes(tk)?'Ring2':['FCX','PLTR'].includes(tk)?'Ring3':avg>=75?'Ring4':'Ring5');
  scoredOps.push({
    ticker:tk, signal_tier:tier, composite_confidence:avg,
    raziel_score:rs, raziel_verdict:verdict, ring, agent_count:ac,
